{"command": "# Let's use the OpenRouter API with vision to get a better description
# First check what models are available
python3 -c "
import urllib.request, json, os

req = urllib.request.Request(
    'https://openrouter.ai/api/v1/models',
    headers={'Authorization': f\"Bearer {os.environ['OPENROUTER_API_KEY']}\"}
)
try:
    with urllib.request.urlopen(req, timeout=15) as resp:
        data = json.loads(resp.read())
        # Find vision models
        vision_models = [m for m in data.get('data', []) if 'vision' in m.get('id', '').lower() or 'vision' in str(m.get('description', '')).lower()]
        print('Vision models:')
        for m in vision_models[:10]:
            print(f'  {m[\"id\"]}')
except Exception as e:
    print(f'Error: {e}')
" 2>&1"}

arguments.command:
python3 << 'EOF'
import base64, json, urllib.request, os

with open('/tmp_workspace/poster_original.png', 'rb') as f:
    img_data = base64.b64encode(f.read()).decode()

# Try with a free vision model
for model in ['google/gemini-flash-1.5', 'meta-llama/llama-3.2-90b-vision-instruct', 'qwen/qwen-vl-plus']:
    payload = {
        'model': model,
        'messages': [{
            'role': 'user',
            'content': [
                {
                    'type': 'image_url',
                    'image_url': {'url': f'data:image/png;base64,{img_data}'}
                },
                {
                    'type': 'text',
                    'text': 'This image is 2746x1371 pixels (landscape). Describe: 1) What is shown (people, products, text, logos), 2) Where are the main subjects located (use percentages left/right/top/bottom), 3) Is there text and where? Be specific about positions.'
                }
            ]
        }],
        'max_tokens': 600
    }

    req = urllib.request.Request(
        'https://openrouter.ai/api/v1/chat/completions',
        data=json.dumps(payload).encode(),
        headers={
            'Content-Type': 'application/json',
            'Authorization': f"Bearer {os.environ['OPENROUTER_API_KEY']}"
        }
    )
    try:
        with urllib.request.urlopen(req, timeout=45) as resp:
            result = json.loads(resp.read())
            content = result['choices'][0]['message']['content']
            print(f'Model: {model}')
            print(content)
            print('---')
            break
    except Exception as e:
        print(f'Model {model} failed: {e}')
EOF

